1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type Step = { op: "quote"; items: Item[] };
8	type Customer = { yearsWithMHPCO: number };
9	type Scenario = { customer: Customer; steps: Step[] };
10	type QuoteResult = { premium: number };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_RATE = 0.2;
18	const LOYALTY_THRESHOLD = 2;
19	const COMPONENT_BASE_PREMIUM = 25;
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	};
29	
30	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
31	
32	const componentGroupBase = (count: number): number =>
33	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
34	
35	const countByType = (items: Item[]): Map<string, number> =>
36	  items.reduce(
37	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
38	    new Map<string, number>(),
39	  );
40	
41	// Returns base premium attributed to a single main item (not components).
42	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
43	
44	// Components are priced per group with block discount.
45	const componentsBaseTotal = (components: Item[]): number =>
46	  [...countByType(components).values()].reduce(
47	    (sum, count) => sum + componentGroupBase(count),
48	    0,
49	  );
50	
51	// Base premium of the whole policy (raw, no item modifiers).
52	const policyBase = (items: Item[]): number => {
53	  const mainBase = items.filter((i) => !isComponent(i)).reduce((sum, i) => sum + itemBasePremium(i), 0);
54	  const compBase = componentsBaseTotal(items.filter(isComponent));
55	  return mainBase + compBase;
56	};
57	
58	const isCursed = (item: Item): boolean => item.cursed === true;
59	const isHighlyEnchanted = (item: Item): boolean =>
60	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
61	
62	// Surcharges that apply to a single item's base premium (cursed, high enchantment).
63	const itemSurcharge = (item: Item): number => {
64	  if (isComponent(item)) return 0;
65	  const base = itemBasePremium(item);
66	  const rate = (isCursed(item) ? CURSE_RATE : 0) + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
67	  return base * rate;
68	};
69	
70	const itemSurchargesTotal = (items: Item[]): number =>
71	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
72	
73	const isLoyal = (customer: Customer): boolean => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
74	
75	const quoteStep = (step: Step, customer: Customer): QuoteResult => {
76	  const base = policyBase(step.items);
77	  const itemSurcharges = itemSurchargesTotal(step.items);
78	  const firstInsurance = base * FIRST_INSURANCE_RATE;
79	  const loyaltyDiscount = isLoyal(customer) ? base * LOYALTY_RATE : 0;
80	  const premium = Math.ceil(base + itemSurcharges + firstInsurance - loyaltyDiscount) + PROCESSING_FEE;
81	  return { premium };
82	};
83	
84	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
85	  const results = scenario.steps.map((step) => quoteStep(step, scenario.customer));
86	  return { results };
87	};
